public boolean canBalance(int[] nums) {
    int totalSum = 0;
    int leftSum = 0;

    for (int i = 0; i < nums.length; i++) {
        totalSum += nums[i];
    }

    for (int i = 0; i < nums.length; i++) {
        leftSum += nums[i];
        if (leftSum == totalSum - leftSum) {
            return true;
        }
    }

    return false;
}

