public String repeatEnd(String str, int n) {
    if (n == 0) {
        return "";
    }

    int strLength = str.length();
    String repeatedEnd = "";

    for (int i = 0; i < n; i++) {
        repeatedEnd += str.substring(strLength - n);
    }

    return repeatedEnd;
}

