public String repeatEnd(String str, int n) {
    if (n < 0 || n > str.length()) {
        return "Invalid input. Please provide a valid value for n.";
    }

    StringBuilder repeatedString = new StringBuilder();
    String lastNCharacters = str.substring(str.length() - n);

