Code:
public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        // Both values are 21 or less
        int diffA = 21 - a;
        int diffB = 21 - b;

        if (diffA >= diffB) {
            return b;
        } else {
            return a;
        }
    }
}

public int[] tenRun(int[] nums) {
    int replacement = 0;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            replacement = nums[i];
        } else if (replacement != 0) {
            nums[i] = replacement;
        }
    }

    return nums;
}

