public String without2(String str) {
    if (str.length() < 2) {
        return str;
    }

    String firstTwoChars = str.substring(0, 2);
    String lastTwoChars = str.substring(str.length() - 2);

    if (firstTwoChars.equals(lastTwoChars)) {
        return str.substring(2);
    } else {
        return str;
    }
}

