public String alarmClock(int day, boolean vacation) {
    if (vacation) {
        if (day >= 1 && day <= 5) { // Weekdays during vacation
            return "10:00";
        } else { // Weekends during vacation
            return "off";
        }
    } else {
        if (day >= 1 && day <= 5) { // Weekdays
            return "7:00";
        } else { // Weekends
            return "10:00";
        }
    }
}

