public boolean sameEnds(int[] nums, int n) {
    if (n == 0) {
        return true;
    }

    boolean areEqual = true;

    for (int i = 0; i < n; i++) {
        if (nums[i] != nums[nums.length - n + i]) {
            areEqual = false;
            break;
        }
    }

    return areEqual;
}

