Code:
public boolean twoTwo(int[] nums) {
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            boolean isAdjacent = false;
            if (i > 0 && nums[i - 1] == 2) {
                isAdjacent = true;
            } else if (i < nums.length - 1 && nums[i + 1] == 2) {
                isAdjacent = true;
            }
            if (!isAdjacent) {
                return false;
            }
        }
    }
    return true;
}

