public boolean canBalance(int[] nums) {
    if (nums.length == 1) {
        return false; // Handle edge case
    }

    int totalSum = 0;
    for (int num : nums) {
        totalSum += num;
    }

    int leftSum = 0;
    for (int i = 0; i < nums.length; i++) {
        leftSum += nums[i];
        if (leftSum == totalSum / 2) {
            return true;
        }
    }

    return false;
}

