    boolean ignoreSection = false;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 6) {
            ignoreSection = true;
            continue;
        }

        if (ignoreSection) {
            if (nums[i] == 7) {
                ignoreSection = false;
            }
            continue;
        }

        sum += nums[i];
    }

    return sum;
}

