public int countClumps(int[] nums) {
    if (nums == null || nums.length == 0) {
        return 0;
    }

    int clumps = 0;
    boolean isClump = false;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[i - 1]) {
            if (!isClump) {
                isClump = true;
                clumps++;
            }
        } else {
            isClump = false;
        }
    }

    return clumps;
}

