public String alarmClock(int day, boolean vacation) {
    if (vacation) {
        if (day >= 1 && day <= 5) {  // Weekday during vacation
            return "10:00";
        } else {  // Weekend during vacation
            return "off";
        }
    } else {
        if (day >= 1 && day <= 5) {  // Weekday not on vacation
            return "7:00";
        } else {  // Weekend not on vacation
            return "10:00";
        }
    }
}

