Code:
public boolean sameEnds(int[] nums, int n) {
    if (n == 0) {
        return true;
    }

    int length = nums.length;
    if (n > length / 2) {
        return false;
    }

    for (int i = 0; i < n; i++) {
        if (nums[i] != nums[length - n + i]) {
            return false;
        }
    }

    return true;
}

public boolean sameEnds(int[] nums, int n) {
    if (n == 0) {
        return true;
    } else if (n > 0 && n <= nums.length) {
        for (int i = 0; i < n; i++) {
            if (nums[i] != nums[nums.length - n + i]) {
                return false;
            }
        }
        return true;
    }
    return false;
}

