public int caughtSpeeding(int speed, boolean isBirthday) {
    int speedLimit = 60;

    if (isBirthday) {
        speedLimit += 5;
    }

    if (speed <= speedLimit) {
        return 0;
    } else if (speed >= speedLimit + 1 && speed <= speedLimit + 20) {
        return 1;
    } else {
        return 2;
    }
}

public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        // Both values are 21 or less
        int diffA = 21 - a;
        int diffB = 21 - b;

        if (diffA >= diffB) {
            return b;
        } else {
            return a;
        }
    }
}

