public boolean canBalance(int[] nums) {
    if (nums.length < 2) {
        return false; // Array should have at least two elements for partitioning
    }

    int totalSum = 0;
    for (int num : nums) {
        totalSum += num;
    }

    int leftSum = 0;
    for (int i = 0; i < nums.length - 1; i++) {
        leftSum += nums[i];
        totalSum -= nums[i];
        if (leftSum == totalSum) {
            return true;
        }
    }

    return false;
}

