    if (nums.length < 2) {
        return nums.length != 1 || nums[0] != 2;
    }

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            if ((i > 0 && nums[i - 1] == 2) || (i < nums.length - 1 && nums[i + 1] == 2)) {
                // 2 is next to another 2
            } else {
                return false;
            }
        }
    }

    return true;
}

