public int countCode(String str) {
    int count = 0;

    if (str.length() < 4) {
        return 0;
    }

    for (int i = 0; i < str.length() - 3; i++) {
        if (str.charAt(i) == 'c' && str.charAt(i + 1) == 'o' && str.charAt(i + 3) == 'e') {
            count++;
        }
    }

    return count;
}

public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        int diffA = 21 - a;
        int diffB = 21 - b;

        if (diffA >= 0 && diffB >= 0) {
            return diffA < diffB ? a : b;
        } else {
            return diffA >= 0 ? a : b;
        }
    }
}

