public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int multipleOf10 = 0;
    boolean changed = false;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            multipleOf10 = nums[i];
            changed = true;
        } else if (changed) {
            nums[i] = multipleOf10;
        }
    }

    return nums;
}

