public int blackjack(int a, int b) {
    if (a > 21 && b > 21) {
        return 0;
    } else if (a > 21) {
        return b;
    } else if (b > 21) {
        return a;
    } else {
        int diffA = 21 - a;
        int diffB = 21 - b;

        if (diffA >= 0 && diffB >= 0) {
            return diffA < diffB ? a : b;
        } else {
            return diffA >= 0 ? a : b;
        }
    }
}

public boolean evenlySpaced(int a, int b, int c) {
    int small, medium, large;

    if ((a >= b && b >= c) || (c >= b && b >= a)) {
        large = b;
        medium = a >= c ? a : c;
        small = a >= c ? c : a;
    } else if ((b >= a && a >= c) || (c >= a && a >= b)) {
        large = a;
        medium = b >= c ? b : c;
        small = b >= c ? c : b;
    } else {
        large = c;
        medium = a >= b ? a : b;
        small = a >= b ? b : a;
    }

    return Math.abs(medium - small) == Math.abs(large - medium);
}

